// Define a class to check Armstrong numbers
class ArmstrongChecker {
    // Static method to check if a number is an Armstrong number
    static isArmstrong(num) {
        const k = num.toString().length; // Number of digits
        let sum = 0;
        let n = num;

        while (n > 0) {
            const ld = n % 10;               // Last digit
            sum += Math.pow(ld, k);          // Add ld^k
            n = Math.floor(n / 10);          // Remove digit
        }

        return sum === num;
    }
}

// Test the class method
const number = 153;

if (ArmstrongChecker.isArmstrong(number)) {
    console.log(`${number} is an Armstrong number.`);
} else {
    console.log(`${number} is not an Armstrong number.`);
}
